def range_step(start, stop, step):
    result = []
    if step > 0:
        if start >= stop:
            return []
        while start < stop:
            result.append(start)
            start += step
    else:
        if start <= stop:
            return []
        while start > stop:
            result.append(start)
            start -= step
    return result
